84	const LUA_CPATH_DEFAULT: &[u8] =
85	    b"./?.so;/usr/local/lib/lua/5.4/?.so;/usr/local/lib/lua/5.4/loadall.so";
86	#[cfg(target_os = "windows")]
87	const LUA_CPATH_DEFAULT: &[u8] = b"./?.dll";
