89	// C: LUA_VERSUFFIX (from luaconf.h) — e.g. "_5_4"
90	// TODO(port): Centralise version constants; this is duplicated from luaconf.h.
91	const LUA_VERSUFFIX: &[u8] = b"_5_4";
