93	// ── Opaque library handle ─────────────────────────────────────────────────────
94	
95	/// Opaque handle to a dynamically loaded C library.
96	///
97	/// C: `void *lib` (the return value of dlopen / LoadLibraryEx).
98	///
99	/// TODO(port): In a real implementation this would be `*mut c_void`. That
100	/// requires `unsafe` which is banned in `lua-stdlib`. Phase B should either
101	/// raise the unsafe budget or introduce a `DynLib` capability object that
102	/// lives in `lua-gc`/`lua-coro` and expose a safe API here.
103	///
104	/// For Phase A this is a `usize` placeholder; all lsys_* functions return
105	/// `None` so no real handle is ever stored.
106	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
107	struct LibHandle(usize);
108	
109	// ── Byte-string utilities ─────────────────────────────────────────────────────
110	
111	/// Append to `buf` the bytes of `s` with all non-overlapping occurrences of
112	/// `pattern` replaced by `replacement`.
113	///
114	/// C: equivalent of the substitution logic inside `luaL_gsub` / `luaL_addgsub`.
115	fn gsub_append(buf: &mut Vec<u8>, s: &[u8], pattern: &[u8], replacement: &[u8]) {
116	    if pattern.is_empty() {
117	        buf.extend_from_slice(s);
118	        return;
119	    }
120	    let mut pos = 0;
121	    while pos < s.len() {
122	        if s[pos..].starts_with(pattern) {
123	            buf.extend_from_slice(replacement);
124	            pos += pattern.len();
125	        } else {
126	            buf.push(s[pos]);
127	            pos += 1;
128	        }
129	    }
130	}
131	
132	/// Return a new `Vec<u8>` with all non-overlapping occurrences of `pattern`
133	/// in `s` replaced by `replacement`.
134	fn gsub_bytes(s: &[u8], pattern: &[u8], replacement: &[u8]) -> Vec<u8> {
135	    let mut out = Vec::new();
136	    gsub_append(&mut out, s, pattern, replacement);
137	    out
138	}
139	
140	/// Find the byte offset of `needle` in `haystack`, or `None`.
141	fn find_subslice(haystack: &[u8], needle: &[u8]) -> Option<usize> {
142	    if needle.is_empty() {
143	        return Some(0);
144	    }
145	    haystack.windows(needle.len()).position(|w| w == needle)
146	}
