148	// ── Platform-specific dynamic-loading stubs ───────────────────────────────────
149	
150	/// Unload a previously loaded C library.
151	///
152	/// C: `static void lsys_unloadlib(void *lib)`
153	///    — POSIX: `dlclose(lib)`; Windows: `FreeLibrary(lib)`.
154	///
155	/// TODO(port): unsafe needed — dlclose/FreeLibrary are FFI calls. Banned in
156	/// lua-stdlib. Phase B: delegate to a DynLib capability or raise unsafe budget.
157	fn lsys_unloadlib(_lib: LibHandle) {
158	    // PORT NOTE: stub — real unloading deferred until the unsafe budget is resolved.
159	}
