161	/// Load a C library from `path`. If `see_glb` is true, make symbols globally
162	/// visible (POSIX RTLD_GLOBAL). On failure, pushes an error string onto `state`.
163	///
164	/// C: `static void *lsys_load(lua_State *L, const char *path, int seeglb)`
165	///    — POSIX: `dlopen(path, RTLD_NOW | (seeglb ? RTLD_GLOBAL : RTLD_LOCAL))`
166	///    — Windows: `LoadLibraryExA(path, NULL, LUA_LLE_FLAGS)`
167	///
168	/// TODO(port): unsafe needed — dlopen/LoadLibraryEx are FFI calls. Banned in
169	/// lua-stdlib. Phase B: delegate to a DynLib capability or raise unsafe budget.
170	fn lsys_load(state: &mut LuaState, _path: &[u8], _see_glb: bool) -> Option<LibHandle> {
171	    // C: lua_pushliteral(L, DLMSG);
172	    let s = state.intern_str(DLMSG).ok()?;
173	    state.push(LuaValue::Str(s));
174	    None
175	}
