177	/// Find symbol `sym` in library `lib` and return it as a Lua C function.
178	/// On failure, pushes an error string onto `state`.
179	///
180	/// C: `static lua_CFunction lsys_sym(lua_State *L, void *lib, const char *sym)`
181	///    — POSIX: `cast_func(dlsym(lib, sym))`
182	///    — Windows: `(lua_CFunction)(voidf)GetProcAddress(lib, sym)`
183	///
184	/// TODO(port): unsafe needed — dlsym/GetProcAddress are FFI calls. Banned in
185	/// lua-stdlib. Phase B: delegate to a DynLib capability or raise unsafe budget.
186	fn lsys_sym(
187	    state: &mut LuaState,
188	    _lib: LibHandle,
189	    _sym: &[u8],
190	) -> Option<fn(&mut LuaState) -> Result<usize, LuaError>> {
191	    // C: lua_pushliteral(L, DLMSG);
192	    let s = state.intern_str(DLMSG).ok()?;
193	    state.push(LuaValue::Str(s));
194	    None
195	}
