197	// ── Path helpers ──────────────────────────────────────────────────────────────
198	
199	/// Return `registry["LUA_NOENV"]` as a boolean.
200	///
201	/// C: `static int noenv(lua_State *L)`
202	fn noenv(state: &mut LuaState) -> bool {
203	    // C: lua_getfield(L, LUA_REGISTRYINDEX, "LUA_NOENV");
204	    state.get_field_registry(b"LUA_NOENV");
205	    // C: b = lua_toboolean(L, -1);
206	    let b = state.to_boolean(-1);
207	    // C: lua_pop(L, 1);
208	    state.pop_n(1);
209	    b
210	}
211	
212	/// Set `package[fieldname]` to the appropriate path value.
213	///
214	/// Priority: versioned env var (e.g. `LUA_PATH_5_4`) → unversioned env var
215	/// (`LUA_PATH`) → compiled-in default. When the env var contains `;;`, the
216	/// compiled-in default is spliced in place of `;;`.
217	///
218	/// C: `static void setpath(lua_State *L, const char *fieldname,
219	///                          const char *envname, const char *dft)`
220	///
221	/// PORT NOTE: C pushes the versioned env-var name string onto the Lua stack
222	/// (via `lua_pushfstring`) and pops it at the end so that `setfield` uses index
223	/// `-3`. In Rust we compute the versioned name without touching the Lua stack,
224	/// so after pushing the final path value the package table is at `-2`. The
225	/// caller must ensure the package table is at stack top when setpath is called.
226	fn setpath(
227	    state: &mut LuaState,
228	    fieldname: &[u8],
229	    envname: &[u8],
230	    dft: &[u8],
231	) -> Result<(), LuaError> {
232	    // C: const char *nver = lua_pushfstring(L, "%s%s", envname, LUA_VERSUFFIX);
233	    let mut nver = envname.to_vec();
234	    nver.extend_from_slice(LUA_VERSUFFIX);
235	
236	    // C: path = getenv(nver);  (then fallback to getenv(envname))
237	    // TODO(port): std::env::var() accepts &str (UTF-8). Env-var names are
238	    // OS-level ASCII here (not Lua user data), so from_utf8 is acceptable, but
239	    // std::env::var_os + std::os::unix::ffi::OsStrExt would be more correct for
240	    // paths containing non-UTF-8 bytes on Unix. Revisit in Phase B.
241	    let nver_str = std::str::from_utf8(&nver).unwrap_or("");
242	    let envname_str = std::str::from_utf8(envname).unwrap_or("");
243	
244	    let path_opt: Option<Vec<u8>> = env::var(nver_str)
245	        .ok()
246	        .map(|s| s.into_bytes())
247	        .or_else(|| env::var(envname_str).ok().map(|s| s.into_bytes()));
248	
249	    let final_path: Vec<u8> = if path_opt.is_none() || noenv(state) {
250	        // C: lua_pushstring(L, dft);
251	        dft.to_vec()
252	    } else {
253	        let path = path_opt.unwrap();
254	        // C: dftmark = strstr(path, LUA_PATH_SEP LUA_PATH_SEP)
255	        let double_sep = [LUA_PATH_SEP, LUA_PATH_SEP];
256	        if let Some(dftmark_pos) = find_subslice(&path, &double_sep) {
257	            // Path contains ";;": replace with default.
258	            // C: luaL_Buffer b; luaL_buffinit(L, &b);
259	            let mut buf = Vec::new();
260	            if dftmark_pos > 0 {
261	                // C: luaL_addlstring(&b, path, dftmark - path);
262	                buf.extend_from_slice(&path[..dftmark_pos]);
263	                // C: luaL_addchar(&b, *LUA_PATH_SEP);
264	                buf.push(LUA_PATH_SEP);
265	            }
266	            // C: luaL_addstring(&b, dft);
267	            buf.extend_from_slice(dft);
268	            let after = dftmark_pos + 2;
269	            if after < path.len() {
270	                // C: luaL_addchar(&b, *LUA_PATH_SEP);
271	                buf.push(LUA_PATH_SEP);
272	                // C: luaL_addlstring(&b, dftmark + 2, (path + len - 2) - dftmark);
273	                buf.extend_from_slice(&path[after..]);
274	            }
275	            // C: luaL_pushresult(&b);
276	            buf
277	        } else {
278	            // C: lua_pushstring(L, path);
279	            path
280	        }
281	    };
282	
283	    // C: setprogdir(L);
284	    // PORT NOTE: On Windows, setprogdir replaces LUA_EXEC_DIR in the path with
285	    // the directory of the running executable (GetModuleFileNameA). On all other
286	    // platforms it's a no-op ((void)0). Stubbed here; on Windows this would also
287	    // require unsafe (Win32 API). The EXEC_DIR substitution is therefore skipped.
288	
289	    // C: lua_setfield(L, -3, fieldname);
290	    // PORT NOTE: In C the index is -3 because the versioned-name string is still
291	    // on the stack. In Rust it is -2 because we did not push the versioned name.
292	    let s = state.intern_str(&final_path)?;
293	    state.push(LuaValue::Str(s));
294	    state.set_field(-2, fieldname)?;
295	
296	    // C: lua_pop(L, 1);  -- pop versioned variable name ('nver')
297	    // PORT NOTE: No nver was pushed in Rust; nothing to pop here.
298	
299	    Ok(())
300	}
301	
302	// ── CLIBS registry table ──────────────────────────────────────────────────────
303	
304	/// Return the library handle stored at `registry._CLIBS[path]`, or `None`.
305	///
306	/// C: `static void *checkclib(lua_State *L, const char *path)`
307	fn checkclib(state: &mut LuaState, path: &[u8]) -> Option<LibHandle> {
308	    // C: lua_getfield(L, LUA_REGISTRYINDEX, CLIBS);
309	    state.get_field_registry(CLIBS);
310	    // C: lua_getfield(L, -1, path);
311	    state.get_field(-1, path);
312	    // C: plib = lua_touserdata(L, -1);
313	    // TODO(port): lua_touserdata extracts a *mut c_void (light userdata). In
314	    // Rust we store LibHandle(usize). When a real implementation stores a pointer
315	    // as a LuaValue::LightUserData, the extraction needs to recover the handle.
316	    let handle = state.to_light_userdata(-1).map(|p| LibHandle(p as usize));
317	    // C: lua_pop(L, 2);
318	    state.pop_n(2);
319	    handle
320	}
321	
322	/// Register a library handle in the CLIBS table (both by path and sequentially).
323	///
324	/// C: `static void addtoclib(lua_State *L, const char *path, void *plib)`
325	fn addtoclib(state: &mut LuaState, path: &[u8], plib: LibHandle) -> Result<(), LuaError> {
326	    // C: lua_getfield(L, LUA_REGISTRYINDEX, CLIBS);
327	    state.get_field_registry(CLIBS);
328	    // C: lua_pushlightuserdata(L, plib);
329	    // TODO(port): In real code plib would be *mut c_void pushed as LightUserData.
330	    // Placeholder: push the usize value as an integer.
331	    state.push(LuaValue::Int(plib.0 as i64));
332	    // C: lua_pushvalue(L, -1);
333	    state.push_value(-1);
334	    // C: lua_setfield(L, -3, path);  -- CLIBS[path] = plib
335	    state.set_field(-3, path)?;
336	    // C: lua_rawseti(L, -2, luaL_len(L, -2) + 1);  -- CLIBS[#CLIBS + 1] = plib
337	    let n = state.len_at(-2);
338	    state.raw_seti(-2, n + 1)?;
339	    // C: lua_pop(L, 1);  -- pop CLIBS table
340	    state.pop_n(1);
341	    Ok(())
342	}
343	
344	/// `__gc` metamethod for the CLIBS table: unloads all registered C libraries
345	/// in reverse order when the Lua state closes.
346	///
347	/// C: `static int gctm(lua_State *L)`
348	fn gctm(state: &mut LuaState) -> Result<usize, LuaError> {
349	    // C: lua_Integer n = luaL_len(L, 1);
350	    let n = state.len_at(1);
351	    let mut i = n;
352	    // C: for (; n >= 1; n--)
353	    while i >= 1 {
354	        // C: lua_rawgeti(L, 1, n);  -- get handle CLIBS[n]
355	        state.raw_geti(1, i)?;
356	        // C: lsys_unloadlib(lua_touserdata(L, -1));
357	        // TODO(port): see checkclib — extracting a real *mut c_void handle needs
358	        // LightUserData support and unsafe casting.
359	        if let Some(handle) = state.to_light_userdata(-1).map(|p| LibHandle(p as usize)) {
360	            lsys_unloadlib(handle);
361	        }
362	        // C: lua_pop(L, 1);
363	        state.pop_n(1);
364	        i -= 1;
365	    }
366	    Ok(0)
367	}
368	
369	// ── Dynamic function lookup ───────────────────────────────────────────────────
370	
371	/// Look for a C function named `sym` in the dynamically loaded library at `path`.
372	///
373	/// On success, pushes the C function (or `true` for `*`-sentinel) and returns `Ok(0)`.
374	/// On non-fatal failure, pushes an error message string and returns `Ok(ERRLIB)`
375	/// or `Ok(ERRFUNC)`. Fatal errors (e.g. OOM) propagate via `Err`.
376	///
377	/// C: `static int lookforfunc(lua_State *L, const char *path, const char *sym)`
378	///
379	/// PORT NOTE: C returns raw `int` error codes. Rust encodes them as `Ok(i32)`
380	/// so the caller can distinguish "error code + message on stack" from "fatal Err".
381	fn lookforfunc(state: &mut LuaState, path: &[u8], sym: &[u8]) -> Result<i32, LuaError> {
382	    // C: void *reg = checkclib(L, path);
383	    let mut reg = checkclib(state, path);
384	    if reg.is_none() {
385	        // C: reg = lsys_load(L, path, *sym == '*');
386	        reg = lsys_load(state, path, sym.first() == Some(&b'*'));
387	        if reg.is_none() {
388	            // C: if (reg == NULL) return ERRLIB;
389	            return Ok(ERRLIB);
390	        }
391	        addtoclib(state, path, reg.unwrap())?;
392	    }
393	    // C: if (*sym == '*') { lua_pushboolean(L, 1); return 0; }
394	    if sym.first() == Some(&b'*') {
395	        state.push(LuaValue::Bool(true));
396	        return Ok(0);
397	    }
398	    // C: lua_CFunction f = lsys_sym(L, reg, sym);
399	    let f = lsys_sym(state, reg.unwrap(), sym);
400	    if let Some(func) = f {
401	        // C: lua_pushcfunction(L, f);
402	        // TODO(phase-b): LuaClosure::LightC currently typed fn() -> i32 in lua-types; use push_c_function until widened.
403	        state.push_c_function(func)?;
404	        Ok(0)
405	    } else {
406	        // C: return ERRFUNC;
407	        Ok(ERRFUNC)
408	    }
409	}
410	
411	// ── Lua-callable package functions ────────────────────────────────────────────
412	
413	/// `package.loadlib(filename, funcname)` — open a C library and return a
414	/// Lua-callable wrapper for `funcname`.
415	///
416	/// Returns: on success, the loader function (1 value).
417	/// On error: `false`, error-message string, and `"open"` or `"init"` (3 values).
418	///
419	/// C: `static int ll_loadlib(lua_State *L)`
420	pub fn ll_loadlib(state: &mut LuaState) -> Result<usize, LuaError> {
421	    // C: const char *path = luaL_checkstring(L, 1);
422	    let path = state.check_arg_string(1)?.to_vec();
423	    // C: const char *init = luaL_checkstring(L, 2);
424	    let init = state.check_arg_string(2)?.to_vec();
425	    // C: int stat = lookforfunc(L, path, init);
426	    let stat = lookforfunc(state, &path, &init)?;
427	    if stat == 0 {
428	        // C: if (l_likely(stat == 0)) return 1;
429	        return Ok(1);
430	    }
431	    // C: luaL_pushfail(L);
432	    // PORT NOTE: luaL_pushfail pushes `false` in Lua 5.4 (changed from nil).
433	    state.push(LuaValue::Bool(false));
434	    // C: lua_insert(L, -2);  -- move fail below error message
435	    state.insert(-2);
436	    // C: lua_pushstring(L, (stat == ERRLIB) ? LIB_FAIL : "init");
437	    let where_bytes: &[u8] = if stat == ERRLIB { LIB_FAIL } else { b"init" };
438	    let where_s = state.intern_str(where_bytes)?;
439	    state.push(LuaValue::Str(where_s));
440	    // C: return 3;
441	    Ok(3)
442	}
443	
444	// ── File existence check ──────────────────────────────────────────────────────
445	
446	/// Try to open `filename` for reading; return `true` if it succeeds.
447	///
448	/// C: `static int readable(const char *filename)`
449	///    — `FILE *f = fopen(filename, "r"); if (f == NULL) return 0;`
450	///
451	/// PORT NOTE: `std::fs` is banned in `lua-stdlib`, so the actual file probe is
452	/// delegated to the embedder-registered `file_loader_hook` on `GlobalState`.
453	/// Without a hook installed, `readable` reports `false` (file system unreachable).
454	fn readable(state: &LuaState, filename: &[u8]) -> bool {
455	    match state.global().file_loader_hook {
456	        Some(hook) => hook(filename).is_ok(),
457	        None => false,
458	    }
459	}
460	
461	// ── Path-component iterator ───────────────────────────────────────────────────
462	
463	/// Iterator over `;`-separated path components.
464	///
465	/// C: `getnextfilename(char **path, char *end)` advanced a mutable pointer
466	/// through a buffer, temporarily zero-terminating each component. In Rust we
467	/// advance a slice reference without mutation.
468	///
469	/// PORT NOTE: The C implementation restored each separator after use (mutating
470	/// the buffer). This Rust version slices immutably, which changes the interface
471	/// but produces the same sequence of filenames.
472	struct PathComponents<'a> {
473	    remaining: &'a [u8],
474	}
475	
476	impl<'a> PathComponents<'a> {
477	    fn new(path: &'a [u8]) -> Self {
478	        PathComponents { remaining: path }
479	    }
480	}
481	
482	impl<'a> Iterator for PathComponents<'a> {
483	    type Item = &'a [u8];
484	
485	    fn next(&mut self) -> Option<Self::Item> {
486	        if self.remaining.is_empty() {
487	            return None;
488	        }
489	        let component = match self.remaining.iter().position(|&b| b == LUA_PATH_SEP) {
490	            Some(sep_pos) => {
491	                let c = &self.remaining[..sep_pos];
492	                self.remaining = &self.remaining[sep_pos + 1..];
493	                c
494	            }
495	            None => {
496	                let c = self.remaining;
497	                self.remaining = &[];
498	                c
499	            }
500	        };
501	        Some(component)
502	    }
503	}
