527	// ── Path search ───────────────────────────────────────────────────────────────
528	
529	/// Search for a readable file matching `name` in the `;`-separated `path`.
530	///
531	/// In each path template, `?` is replaced by `name` (with `sep` bytes replaced
532	/// by `dirsep` first). Returns `Some(filename_bytes)` and pushes the filename
533	/// string on the Lua stack if found. Returns `None` and pushes an error message
534	/// string if not found.
535	///
536	/// C: `static const char *searchpath(lua_State *L, const char *name,
537	///                                    const char *path, const char *sep,
538	///                                    const char *dirsep)`
539	fn searchpath(
540	    state: &mut LuaState,
541	    name: &[u8],
542	    path: &[u8],
543	    sep: &[u8],
544	    dirsep: &[u8],
545	) -> Result<Option<Vec<u8>>, LuaError> {
546	    // C: if (*sep != '\0' && strchr(name, *sep) != NULL)
547	    //        name = luaL_gsub(L, name, sep, dirsep);
548	    let name_buf: Vec<u8> = if !sep.is_empty() && name.contains(&sep[0]) {
549	        gsub_bytes(name, sep, dirsep)
550	    } else {
551	        name.to_vec()
552	    };
553	
554	    // C: luaL_buffinit(L, &buff);
555	    // C: luaL_addgsub(&buff, path, LUA_PATH_MARK, name);
556	    // Build pathname list: replace every '?' in path with the (adjusted) name.
557	    let pathname: Vec<u8> = gsub_bytes(path, &[LUA_PATH_MARK], &name_buf);
558	
559	    // C: while ((filename = getnextfilename(&pathname, endpathname)) != NULL)
560	    for filename in PathComponents::new(&pathname) {
561	        // C: if (readable(filename)) return lua_pushstring(L, filename);
562	        if readable(state, filename) {
563	            let s = state.intern_str(filename)?;
564	            state.push(LuaValue::Str(s));
565	            return Ok(Some(filename.to_vec()));
566	        }
567	    }
568	
569	    // C: luaL_pushresult(&buff);          -- push expanded path list
570	    // C: pusherrornotfound(L, lua_tostring(L, -1));
571	    // PORT NOTE: C uses the Lua-stack string of the expanded pathname as the
572	    // argument to pusherrornotfound. In Rust we have `pathname` already as a
573	    // Vec<u8>; we pass it directly without the round-trip through the Lua stack.
574	    pusherrornotfound(state, &pathname)?;
575	    Ok(None)
576	}
