730	/// Try to load `modname`'s open function from the C dynamic library at `filename`.
731	///
732	/// Handles the "ignore mark" (`-`) convention: `"foo-bar"` first tries
733	/// `luaopen_foo`, then `luaopen_bar` as a fallback.
734	///
735	/// C: `static int loadfunc(lua_State *L, const char *filename, const char *modname)`
736	fn loadfunc(state: &mut LuaState, filename: &[u8], modname: &[u8]) -> Result<i32, LuaError> {
737	    // C: modname = luaL_gsub(L, modname, ".", LUA_OFSEP);
738	    let modname: Vec<u8> = gsub_bytes(modname, b".", LUA_OFSEP);
739	
740	    // C: mark = strchr(modname, *LUA_IGMARK);
741	    if let Some(mark_pos) = modname.iter().position(|&b| b == LUA_IGMARK) {
742	        // C: openfunc = lua_pushlstring(L, modname, mark - modname);
743	        let prefix = &modname[..mark_pos];
744	        // C: openfunc = lua_pushfstring(L, LUA_POF"%s", openfunc);
745	        let mut openfunc = LUA_POF.to_vec();
746	        openfunc.extend_from_slice(prefix);
747	        // C: stat = lookforfunc(L, filename, openfunc);
748	        let stat = lookforfunc(state, filename, &openfunc)?;
749	        if stat != ERRFUNC {
750	            // C: if (stat != ERRFUNC) return stat;
751	            return Ok(stat);
752	        }
753	        // C: modname = mark + 1;  -- else go ahead and try old-style name
754	        let tail = &modname[mark_pos + 1..];
755	        let mut openfunc2 = LUA_POF.to_vec();
756	        openfunc2.extend_from_slice(tail);
757	        return lookforfunc(state, filename, &openfunc2);
758	    }
759	
760	    // C: openfunc = lua_pushfstring(L, LUA_POF"%s", modname);
761	    let mut openfunc = LUA_POF.to_vec();
762	    openfunc.extend_from_slice(&modname);
763	    lookforfunc(state, filename, &openfunc)
764	}
