784	/// Searcher that looks in `package.cpath` using only the root component
785	/// (everything before the first `.`) of the module name.
786	///
787	/// C: `static int searcher_Croot(lua_State *L)`
788	fn searcher_croot(state: &mut LuaState) -> Result<usize, LuaError> {
789	    // C: const char *name = luaL_checkstring(L, 1);
790	    let name = state.check_arg_string(1)?.to_vec();
791	    // C: const char *p = strchr(name, '.');
792	    let dot_pos = name.iter().position(|&b| b == b'.');
793	    if dot_pos.is_none() {
794	        // C: if (p == NULL) return 0;  -- is already root; not our responsibility
795	        return Ok(0);
796	    }
797	    let dot_pos = dot_pos.unwrap();
798	
799	    // C: lua_pushlstring(L, name, p - name);  -- push root portion
800	    let root = &name[..dot_pos];
801	    let root_s = state.intern_str(root)?;
802	    state.push(LuaValue::Str(root_s));
803	
804	    // C: filename = findfile(L, lua_tostring(L, -1), "cpath", LUA_CSUBSEP);
805	    // PORT NOTE: C reads the root string back from the stack; in Rust we use
806	    // the slice directly and then pop the stack entry below.
807	    let filename = findfile(state, root, b"cpath", LUA_CSUBSEP)?;
808	    // Pop the root string we pushed above (findfile does not consume it).
809	    state.pop_n(1);
810	
811	    if filename.is_none() {
812	        // C: if (filename == NULL) return 1;
813	        return Ok(1);
814	    }
815	    let filename = filename.unwrap();
816	
817	    // C: if ((stat = loadfunc(L, filename, name)) != 0) { ... }
818	    let stat = loadfunc(state, &filename, &name)?;
819	    if stat != 0 {
820	        if stat != ERRFUNC {
821	            // C: return checkload(L, 0, filename);  -- real error
822	            return checkload(state, false, &filename);
823	        } else {
824	            // C: lua_pushfstring(L, "no module '%s' in file '%s'", name, filename);
825	            // C: return 1;
826	            let mut msg = b"no module '".to_vec();
827	            msg.extend_from_slice(&name);
828	            msg.extend_from_slice(b"' in file '");
829	            msg.extend_from_slice(&filename);
830	            msg.push(b'\'');
831	            let s = state.intern_str(&msg)?;
832	            state.push(LuaValue::Str(s));
833	            return Ok(1);
834	        }
835	    }
836	
837	    // C: lua_pushstring(L, filename);  -- 2nd argument to module
838	    let s = state.intern_str(&filename)?;
839	    state.push(LuaValue::Str(s));
840	    // C: return 2;
841	    Ok(2)
842	}
