844	/// Searcher that looks in `package.preload` for a pre-registered loader.
845	///
846	/// C: `static int searcher_preload(lua_State *L)`
847	fn searcher_preload(state: &mut LuaState) -> Result<usize, LuaError> {
848	    // C: const char *name = luaL_checkstring(L, 1);
849	    let name = state.check_arg_string(1)?.to_vec();
850	    // C: lua_getfield(L, LUA_REGISTRYINDEX, LUA_PRELOAD_TABLE);
851	    state.get_field_registry(b"_PRELOAD");
852	    // C: if (lua_getfield(L, -1, name) == LUA_TNIL) { ... }
853	    let ty = state.get_field(-1, &name)?;
854	    if ty == LuaType::Nil {
855	        // C: lua_pushfstring(L, "no field package.preload['%s']", name);
856	        let mut msg = b"no field package.preload['".to_vec();
857	        msg.extend_from_slice(&name);
858	        msg.push(b'\'');
859	        msg.push(b']');
860	        let s = state.intern_str(&msg)?;
861	        state.push(LuaValue::Str(s));
862	        // C: return 1;
863	        return Ok(1);
864	    }
865	    // C: lua_pushliteral(L, ":preload:");
866	    let tag = state.intern_str(b":preload:")?;
867	    state.push(LuaValue::Str(tag));
868	    // C: return 2;
869	    Ok(2)
870	}
