966	/// `require(modname)` — load a module by name, using `package.loaded` as a
967	/// cache and `package.searchers` to find and load it if not already cached.
968	///
969	/// Returns the module value (and optionally the loader data) — 2 values.
970	///
971	/// C: `static int ll_require(lua_State *L)`
972	pub fn ll_require(state: &mut LuaState) -> Result<usize, LuaError> {
973	    // C: const char *name = luaL_checkstring(L, 1);
974	    let name = state.check_arg_string(1)?.to_vec();
975	
976	    // C: lua_settop(L, 1);  -- LOADED table will be at index 2
977	    // PORT NOTE: must use the public-API `set_top` (relative to the current
978	    // C-frame's `func`), not `LuaState::set_top` which is an inherent that
979	    // sets an absolute stack index and would truncate the entire stack.
980	    lua_vm::api::set_top(state, 1)?;
981	
982	    // C: lua_getfield(L, LUA_REGISTRYINDEX, LUA_LOADED_TABLE);
983	    state.get_field_registry(b"_LOADED")?;
984	
985	    // C: lua_getfield(L, 2, name);  -- LOADED[name]
986	    state.get_field(2, &name)?;
987	
988	    // C: if (lua_toboolean(L, -1)) return 1;  -- package is already loaded
989	    if state.to_boolean(-1) {
990	        return Ok(1);
991	    }
992	
993	    // C: lua_pop(L, 1);  -- remove 'getfield' result
994	    state.pop_n(1);
995	
996	    // C: findloader(L, name);
997	    // After this, the stack has: [name(1), LOADED(2), searchers(3), loader(-2), loaderdata(-1)]
998	    findloader(state, &name)?;
999	
1000	    // C: lua_rotate(L, -2, 1);  -- function <-> loader data
1001	    // Swaps loader and loaderdata: [..., loaderdata, loader]
1002	    state.rotate(-2, 1);
1003	
1004	    // C: lua_pushvalue(L, 1);  -- name is 1st argument to module loader
1005	    state.push_value(1);
1006	
1007	    // C: lua_pushvalue(L, -3);  -- loader data is 2nd argument
1008	    // PORT NOTE: After the rotate, loaderdata is 3 from top (-3). In C this is
1009	    // at absolute index 4 (but C uses the pre-rotate layout). TODO(port): verify.
1010	    state.push_value(-3);
1011	
1012	    // C: lua_call(L, 2, 1);  -- run loader to load module
1013	    state.call(2, 1)?;
1014	
1015	    // C: if (!lua_isnil(L, -1)) lua_setfield(L, 2, name);
1016	    if state.type_at(-1) != LuaType::Nil {
1017	        state.set_field(2, &name)?;
1018	    } else {
1019	        // C: else lua_pop(L, 1);
1020	        state.pop_n(1);
1021	    }
1022	
1023	    // C: if (lua_getfield(L, 2, name) == LUA_TNIL) { ... module set no value }
1024	    let ty = state.get_field(2, &name)?;
1025	    if ty == LuaType::Nil {
1026	        // C: lua_pushboolean(L, 1); lua_copy(L, -1, -2); lua_setfield(L, 2, name);
1027	        state.push(LuaValue::Bool(true));
1028	        state.copy_value(-1, -2);
1029	        state.set_field(2, &name)?;
1030	    }
1031	
1032	    // C: lua_rotate(L, -2, 1);  -- loader data <-> module result
1033	    state.rotate(-2, 1);
1034	
1035	    // C: return 2;  -- return module result and loader data
1036	    Ok(2)
1037	}
1038	
1039	// ── Package library setup ─────────────────────────────────────────────────────
1040	
1041	/// Create the `searchers` table and install the four built-in searchers, each
1042	/// with the `package` table as upvalue #1.
1043	///
1044	/// C: `static void createsearcherstable(lua_State *L)`
1045	fn createsearcherstable(state: &mut LuaState) -> Result<(), LuaError> {
1046	    // C: static const lua_CFunction searchers[] = { searcher_preload,
1047	    //        searcher_Lua, searcher_C, searcher_Croot, NULL };
1048	    let searchers: &[fn(&mut LuaState) -> Result<usize, LuaError>] = &[
1049	        searcher_preload,
1050	        searcher_lua,
1051	        searcher_c,
1052	        searcher_croot,
1053	    ];
1054	
1055	    // C: lua_createtable(L, sizeof(searchers)/sizeof(searchers[0]) - 1, 0);
1056	    state.create_table(searchers.len() as i32, 0);
1057	
1058	    // C: for (i=0; searchers[i] != NULL; i++) { ... lua_pushcclosure(L, searchers[i], 1); ... }
1059	    for (i, &f) in searchers.iter().enumerate() {
1060	        // C: lua_pushvalue(L, -2);  -- set 'package' as upvalue for all searchers
1061	        state.push_value(-2);
1062	        // C: lua_pushcclosure(L, searchers[i], 1);
1063	        // TODO(port): push_c_closure takes the function and n upvalues from the
1064	        //             stack. The package table upvalue must be correctly associated
1065	        //             with each searcher closure so that findfile can access it
1066	        //             via lua_upvalueindex(1). Verify in Phase B.
1067	        state.push_c_closure(f, 1)?;
1068	        // C: lua_rawseti(L, -2, i+1);
1069	        state.raw_seti(-2, (i + 1) as i64)?;
1070	    }
1071	    // C: lua_setfield(L, -2, "searchers");
1072	    state.set_field(-2, b"searchers")?;
1073	    Ok(())
1074	}
1075	
1076	/// Create the `_CLIBS` registry table with a `__gc` finalizer that closes all
1077	/// loaded C libraries when the Lua state is closed.
1078	///
1079	/// C: `static void createclibstable(lua_State *L)`
1080	fn createclibstable(state: &mut LuaState) -> Result<(), LuaError> {
1081	    // C: luaL_getsubtable(L, LUA_REGISTRYINDEX, CLIBS);
1082	    state.get_subtable_registry(CLIBS)?;
1083	    // C: lua_createtable(L, 0, 1);  -- metatable for CLIBS
1084	    state.create_table(0, 1);
1085	    // C: lua_pushcfunction(L, gctm);
1086	    // TODO(phase-b): LuaClosure::LightC currently typed fn() -> i32 in lua-types; use push_c_function until widened.
1087	    state.push_c_function(gctm)?;
1088	    // C: lua_setfield(L, -2, "__gc");
1089	    state.set_field(-2, b"__gc")?;
1090	    // C: lua_setmetatable(L, -2);
1091	    state.set_metatable(-2)?;
1092	    Ok(())
1093	}
1094	
1095	/// Open the `package` library and return the `package` table.
1096	///
1097	/// C: `LUAMOD_API int luaopen_package(lua_State *L)`
1098	pub fn luaopen_package(state: &mut LuaState) -> Result<usize, LuaError> {
1099	    // C: createclibstable(L);
1100	    createclibstable(state)?;
1101	
1102	    // C: luaL_newlib(L, pk_funcs);  -- create 'package' table
1103	    // PORT NOTE: The C pk_funcs table also contains placeholder entries for
1104	    // "preload", "cpath", "path", "searchers", "loaded" (all NULL). In Rust
1105	    // those fields are set explicitly below; only the real functions are here.
1106	    state.new_lib(&[
1107	        (b"loadlib" as &[u8], ll_loadlib as fn(&mut LuaState) -> Result<usize, LuaError>),
1108	        (b"searchpath", ll_searchpath as fn(&mut LuaState) -> Result<usize, LuaError>),
1109	    ])?;
1110	
1111	    // C: createsearcherstable(L);
1112	    createsearcherstable(state)?;
1113	
1114	    // C: setpath(L, "path", LUA_PATH_VAR, LUA_PATH_DEFAULT);
1115	    setpath(state, b"path", LUA_PATH_VAR, LUA_PATH_DEFAULT)?;
1116	
1117	    // C: setpath(L, "cpath", LUA_CPATH_VAR, LUA_CPATH_DEFAULT);
1118	    setpath(state, b"cpath", LUA_CPATH_VAR, LUA_CPATH_DEFAULT)?;
1119	
1120	    // C: lua_pushliteral(L, LUA_DIRSEP "\n" LUA_PATH_SEP "\n" LUA_PATH_MARK "\n"
1121	    //                       LUA_EXEC_DIR "\n" LUA_IGMARK "\n");
1122	    // The config string encodes platform separator characters, one per line.
1123	    let mut config: Vec<u8> = Vec::new();
1124	    config.push(LUA_DIRSEP);
1125	    config.push(b'\n');
1126	    config.push(LUA_PATH_SEP);
1127	    config.push(b'\n');
1128	    config.push(LUA_PATH_MARK);
1129	    config.push(b'\n');
1130	    config.push(b'!');   // LUA_EXEC_DIR
1131	    config.push(b'\n');
1132	    config.push(LUA_IGMARK);
1133	    config.push(b'\n');
1134	    let config_s = state.intern_str(&config)?;
1135	    state.push(LuaValue::Str(config_s));
1136	
1137	    // C: lua_setfield(L, -2, "config");
1138	    state.set_field(-2, b"config")?;
1139	
1140	    // C: luaL_getsubtable(L, LUA_REGISTRYINDEX, LUA_LOADED_TABLE);
1141	    state.get_subtable_registry(b"_LOADED")?;
1142	    // C: lua_setfield(L, -2, "loaded");
1143	    state.set_field(-2, b"loaded")?;
1144	
1145	    // C: luaL_getsubtable(L, LUA_REGISTRYINDEX, LUA_PRELOAD_TABLE);
1146	    state.get_subtable_registry(b"_PRELOAD")?;
1147	    // C: lua_setfield(L, -2, "preload");
1148	    state.set_field(-2, b"preload")?;
1149	
1150	    // C: lua_pushglobaltable(L);
1151	    state.push_globals();
1152	    // C: lua_pushvalue(L, -2);  -- set 'package' as upvalue for next lib
1153	    state.push_value(-2);
1154	    // C: luaL_setfuncs(L, ll_funcs, 1);  -- open lib into global table
1155	    state.set_funcs_with_upvalues(
1156	        &[(b"require" as &[u8], ll_require as fn(&mut LuaState) -> Result<usize, LuaError>)],
1157	        1,
1158	    )?;
1159	    // C: lua_pop(L, 1);  -- pop global table
1160	    state.pop_n(1);
1161	
1162	    // C: return 1;  -- return 'package' table
1163	    Ok(1)
1164	}
1165	
1166	// ──────────────────────────────────────────────────────────────────────────────
1167	// PORT STATUS
1168	//   source:        src/loadlib.c  (758 lines, 25 functions)
1169	//   target_crate:  lua-stdlib
1170	//   confidence:    medium
1171	//   todos:         11
1172	//   port_notes:    6
1173	//   unsafe_blocks: 0   (must be 0 outside lua-gc/lua-coro)
1174	//   notes:         All three lsys_* platform backends are stubs (unsafe needed
1175	//                  for dlopen/LoadLibraryEx; banned in lua-stdlib). readable()
1176	//                  is a stub (std::fs banned in lua-stdlib). searcher_lua is
1177	//                  also a stub (no load_file yet). The path-finding and
1178	//                  require logic are faithfully ported. Stack index arithmetic
1179	//                  in findloader/ll_require should be verified in Phase B.
1180	//                  LUA_PATH_DEFAULT / LUA_CPATH_DEFAULT are hardcoded and
1181	//                  must be replaced with platform configuration constants.
1182	// ──────────────────────────────────────────────────────────────────────────────
