85	fn e_tag(e: &LuaError) -> &'static str {
86	    match e {
87	        LuaError::Runtime(_) => "Runtime",
88	        LuaError::Syntax(_)  => "Syntax",
89	        LuaError::Memory     => "Memory",
90	        LuaError::Error      => "Error",
91	        LuaError::Yield      => "Yield",
92	        LuaError::File       => "File",
93	        LuaError::Gc         => "Gc",
94	    }
95	}
96	
97	fn main() -> ExitCode {
98	    let args_os: Vec<std::ffi::OsString> = std::env::args_os().collect();
99	    if args_os.len() < 2 {
100	        let prog = args_os
101	            .first()
102	            .map(|s| s.to_string_lossy().into_owned())
103	            .unwrap_or_else(|| "lua-rs".to_string());
104	        eprintln!("usage: {} '<lua source>'", prog);
105	        eprintln!("example: {} 'print(\"hello\")'", prog);
106	        return ExitCode::from(2);
107	    }
108	    #[cfg(unix)]
109	    let source: Vec<u8> = {
110	        use std::os::unix::ffi::OsStrExt;
111	        args_os[1].as_bytes().to_vec()
112	    };
113	    #[cfg(not(unix))]
114	    let source: Vec<u8> = args_os[1].to_string_lossy().into_owned().into_bytes();
115	
116	    eprintln!("[1/4] Creating LuaState...");
117	    let result = catch_unwind(AssertUnwindSafe(|| {
118	        let mut state = new_state().ok_or("new_state returned None")?;
119	        state.global_mut().parser_hook = Some(parser_hook);
120	        state.global_mut().file_loader_hook = Some(file_loader_hook);
121	
122	        eprintln!("[2/4] Opening standard library...");
123	        open_libs(&mut state).map_err(|e| format!("open_libs failed: {}", render_lua_error(&e)))?;
124	
125	        eprintln!("[3/4] Loading source (parse + compile)...");
126	        let status = load_string(&mut state, &source)
127	            .map_err(|e| format!("load_string failed: {}", render_lua_error(&e)))?;
128	        if status != 0 {
129	            let msg = match to_lua_string(&mut state, -1) {
130	                Ok(Some(s)) => String::from_utf8_lossy(s.as_bytes()).into_owned(),
131	                _ => "(no error message on stack)".to_string(),
132	            };
133	            return Err(format!(
134	                "Syntax: {} (load_string status={})",
135	                msg, status
136	            ));
137	        }
138	
139	        eprintln!("[4/4] Executing chunk...");
140	        let final_status = pcall_k(&mut state, 0, MULTRET, 0, 0, None)
141	            .map_err(|e| format!("pcall_k failed: {}", render_lua_error(&e)))?;
142	
143	        Ok::<_, String>(final_status)
144	    }));
145	
146	    match result {
147	        Ok(Ok(status)) => {
148	            eprintln!("[ok] execution completed, status={:?}", status);
149	            ExitCode::SUCCESS
150	        }
151	        Ok(Err(msg)) => {
152	            eprintln!("[err] {}", msg);
153	            ExitCode::from(1)
154	        }
155	        Err(panic) => {
156	            let msg = if let Some(s) = panic.downcast_ref::<String>() {
157	                s.clone()
158	            } else if let Some(s) = panic.downcast_ref::<&str>() {
159	                s.to_string()
160	            } else {
161	                "(non-string panic payload)".to_string()
162	            };
163	            eprintln!("[panic] {}", msg);
164	            ExitCode::from(101)
165	        }
166	    }
167	}
168	
